input bit stream. When the sequence is found, it should set
start_shifting to 1, forever, until reset. Reset is active high
synchronous.

module TopModule (
  input clk,
  input reset,
  input data,
  output start_shifting
);module TopModule (
  input clk,
  input reset,
  input data,
  output start_shifting
);

  parameter [2:0] S0 = 3'b000;  // Initial state
  parameter [2:0] S1 = 3'b001;  // Matched '1'
  parameter [2:0] S2 = 3'b010;  // Matched '11'
  parameter [2:0] S3 = 3'b011;  // Matched '110'
  parameter [2:0] S4 = 3'b100;  // Matched '1101'

  reg [2:0] state;
  reg start_shifting;

  always @(posedge clk) begin
    if (reset) begin
      state <= S0;
      start_shifting <= 0;
    end else begin
      case (state)
        S0: begin
          if (data) begin
            state <= S1;
            start_shifting <= 0;
          end else begin
            state <= S0;
            start_shifting <= 0;
          end
        end
        S1: begin
          if (data) begin
            state <= S2;
            start_shifting <= 0;
          end else begin
            state <= S0;
            start_shifting <= 0;
          end
        end
        S2: begin
          if (data) begin
            state <= S3;
            start_shifting <= 0;
          end else begin
            state <= S0;
            start_shifting <= 0;
          end
        end
        S3: begin
          if (data) begin
            state <= S4;
            start_shifting <= 1;
          end else begin
            state <= S0;
            start_shifting <= 0;
          end
        end
        S4: begin
          if (data) begin
            state <= S3;
            start_shifting <= 1;
          end else begin
            state <= S0;
            start_shifting <= 0;
          end
        end
      endcase
    end
  end

endmodule

