module TopModule (
  input clk,
  input load,
  input [511:0] data,
  output reg [511:0] q
);

  always @(posedge clk) begin
    if (load) begin
      q <= data;
    end else begin
      reg [2:0] left, center, right;
      reg [2:0] next_state;
      reg [511:0] next_q;

      for (int i = 0; i < 512; i = i + 1) begin
        left = {q[i-1], 1'b0}; // Left neighbor, with boundary as 0
        center = q[i];
        right = {1'b0, q[i+1]}; // Right neighbor, with boundary as 0

        // Compute next state using the XOR of left and right
        next_state = left ^ right;

        next_q[i] = next_state[0]; // Only the least significant bit is used
      end
      q <= next_q;
    end
  end

endmodule

