  input areset,
  input predict_valid,
  input predict_taken,
  output logic [31:0] predict_history,

  input train_mispredicted,
  input train_taken,
  input [31:0] train_history
);

  logic [31:0] history_reg;
  logic [31:0] history_next;

  always @(posedge clk or posedge areset) begin
    if (areset) begin
      history_reg <= 32'h0;
    end else begin
      history_next = history_reg;
      if (train_mispredicted) begin
        // Load history with history before mispredicted branch
        // concatenated with actual result of the branch
        history_next = {train_history, train_taken};
      end else if (predict_valid) begin
        // Shift in predict_taken to LSB
        history_next = {predict_taken, history_reg[30:0]};
      end
      history_reg <= history_next;
    end
  end

  assign predict_history = history_reg;

endmodule

