        if (reset) begin
            q_reg <= 32'h1;
        end else begin
            // Galois LFSR with taps at positions 32, 22, 2, and 1
            // q_reg[31] is the LSB, so we need to shift right and XOR
            reg [31:0] next_q;
            next_q = q_reg >> 1;
            next_q[0] = q_reg[31] ^ q_reg[21] ^ q_reg[1] ^ q_reg[0];
            q_reg <= next_q;
        end
    end

    assign q = q_reg;

