    always @(posedge clk) begin
        if (load) begin
            q_reg <= data;
        end else begin
            q_reg <= q_next;
        end
    end

    always @* begin
        q_next = 0;
        for (int i = 0; i < 512; i = i + 1) begin
            // Left neighbor is q_reg[i-1] if i > 0, else 0
            // Right neighbor is q_reg[i+1] if i < 511, else 0
            // Center is q_reg[i]
